 12→import { Image } from "expo-image";
 13→import { router } from "expo-router";
 14→import { useCallback, useRef, useState, type JSX } from "react";
 15→import { KeyboardAvoidingView, Platform, StyleSheet, View } from "react-native";
 16→
 17→export function AddRecipeForm({
 18→  photoUri,
 19→  source,
 20→  onSourceChange,
 21→  onConfirm,
 22→}: {
 23→  photoUri: PhotoUri;
 24→  source: SourceId;
 25→  onSourceChange: (sourceId: SourceId, isAutomatic?: boolean) => void;
 26→  onConfirm: (sourceOverride?: SourceId) => void;
 27→}): JSX.Element {
 28→  const theme = useTheme();
 29→  const { t } = useTranslation();
 30→  const sourceSelectorRef = useRef<SourceSelectorRef>(null);
 31→  const [isEditingSource, setIsEditingSource] = useState(false);
 32→
 33→  const handleEditingChange = useCallback((editing: boolean) => {
 34→    setIsEditingSource(editing);
 35→  }, []);
 36→
 37→  const handleClose = useCallback(() => {
 38→    if (isEditingSource) {
 39→      const cancelled = sourceSelectorRef.current?.cancelEdit();
 40→      if (cancelled) return;
 41→    }
 42→    if (Platform.OS !== "web") {
 43→      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
 44→    }
 45→    Alert.alert(
 46→      t("recipeForm.discardChanges.title"),
 47→      t("recipeForm.discardChanges.message"),
 48→      [
 49→        { text: t("recipeForm.discardChanges.cancel"), style: "cancel" },
 50→        {
 51→          text: t("recipeForm.discardChanges.discard"),
 52→          style: "destructive",
 53→          onPress: () => {
 54→            if (Platform.OS !== "web") {
 55→              Haptics.notificationAsync(
 56→                Haptics.NotificationFeedbackType.Warning
 57→              );
 58→            }
 59→            router.back();
 60→          },
 61→        },
 62→      ]
 63→    );
 64→  }, [isEditingSource, t]);
 65→
 66→  const handleConfirm = useCallback(async () => {
 67→    if (isEditingSource) {
 68→      const confirmed = await sourceSelectorRef.current?.confirmNewSource();
 69→      if (!confirmed) return;
 70→      onConfirm(confirmed);
 71→      return;
 72→    }
 73→    if (!source) return;
 74→    onConfirm();
 75→  }, [isEditingSource, source, onConfirm]);
 76→
 77→  return (
 78→    <KeyboardAvoidingView
 79→      style={[styles.container, getThemeColors(theme).container]}
 80→      behavior={Platform.OS === "ios" ? "padding" : "height"}
 81→    >
 82→      <View style={styles.processingContainer}>
 83→        <Image
 84→          source={{ uri: photoUri }}
 85→          style={styles.processingImage}
 86→          contentFit="cover"
 87→        />
 88→        <View style={styles.processingBottomBar}>
 89→          <LiquidGlassButton
 90→            onPress={handleClose}
 91→            accessibilityLabel={t("accessibility.close")}
 92→            systemImage="xmark"
 93→          />
 94→          <SourceSelector
 95→            ref={sourceSelectorRef}
 96→            value={source}
 97→            onValueChange={onSourceChange}
 98→            onEditingChange={handleEditingChange}
 99→          />
100→          <ConfirmButton
101→            onConfirm={handleConfirm}
102→            disabled={!isEditingSource && !source}
103→          />
104→        </View>
105→      </View>
106→    </KeyboardAvoidingView>
107→  );
